import javax.swing.*;
public class MultiListener {
    public static void main(String[] args) {
        JButton btn = new JButton("Go");
        btn.addActionListener(e -> System.out.println("listener A"));
        btn.addActionListener(e -> System.out.println("listener B"));
        btn.doClick();
        System.out.println("listeners: " + btn.getActionListeners().length);
    }
}
